# Module defining the animal hierarchy
# Demonstrates abstract base classes and virtual methods

@abstract
class Animal:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def speak(self) -> str:
        ...

    @virtual
    def description(self) -> str:
        return f"Animal named {self.name}"

class Dog(Animal):
    breed: str

    def __init__(self, name: str, breed: str):
        super().__init__(name)
        self.breed = breed

    @override
    def speak(self) -> str:
        return "Woof!"

    @override
    def description(self) -> str:
        return f"{self.breed} dog named {self.name}"

class Cat(Animal):
    color: str

    def __init__(self, name: str, color: str):
        super().__init__(name)
        self.color = color

    @override
    def speak(self) -> str:
        return "Meow!"

    @override
    def description(self) -> str:
        return f"{self.color} cat named {self.name}"

