# Farm module - manages collections of animals
# Demonstrates importing and using classes from another module

from animals import Animal, Dog, Cat

class Farm:
    animals: list[Animal]
    farm_name: str

    def __init__(self, farm_name: str):
        self.farm_name = farm_name
        self.animals = []

    def add_animal(self, animal: Animal):
        self.animals.append(animal)

    def get_animal_count(self) -> int:
        return len(self.animals)

    def make_all_speak(self):
        for animal in self.animals:
            sound: str = animal.speak()
            desc: str = animal.description()
            print(f"{desc} says: {sound}")

    def get_summary(self) -> str:
        count: int = self.get_animal_count()
        return f"{self.farm_name} has {count} animals"

class Kennel(Farm):
    max_capacity: int

    def __init__(self, farm_name: str, max_capacity: int):
        super().__init__(farm_name)
        self.max_capacity = max_capacity

    @override
    def get_summary(self) -> str:
        base: str = super().get_summary()
        return f"{base} (max capacity: {self.max_capacity})"

    def has_space(self) -> bool:
        return self.get_animal_count() < self.max_capacity
